class RebirthRewards{constructor(){this.rebirthUpgrades=this.initializeUpgrades()}initializeUpgrades(){return{efficientGathering:{name:"Efficient Gathering",description:"+10% gathering speed per rebirth",minRebirths:1,baseCost:5,costGrowth:2,maxLevel:10,effect:e=>({gatheringSpeed:1+.1*e})},quickCrafting:{name:"Quick Crafting",description:"+8% crafting speed per rebirth",minRebirths:1,baseCost:5,costGrowth:2,maxLevel:10,effect:e=>({craftingSpeed:1+.08*e})},shrewdTrader:{name:"Shrewd Trader",description:"+5% selling price per level",minRebirths:1,baseCost:10,costGrowth:2.2,maxLevel:8,effect:e=>({sellingBonus:1+.05*e})},masterCrafter:{name:"Master Crafter",description:"5% chance to craft 2x items",minRebirths:2,baseCost:20,costGrowth:2.5,maxLevel:5,effect:e=>({doubleCraftChance:.05*e})},luckyFind:{name:"Lucky Find",description:"3% chance to find 2x resources",minRebirths:2,baseCost:15,costGrowth:2.5,maxLevel:5,effect:e=>({doubleGatherChance:.03*e})},fastLearner:{name:"Fast Learner",description:"+15% worker efficiency per level",minRebirths:2,baseCost:25,costGrowth:2.8,maxLevel:6,effect:e=>({workerEfficiency:1+.15*e})},bulkProduction:{name:"Bulk Production",description:"Auto-craft 2 items simultaneously",minRebirths:3,baseCost:50,costGrowth:3,maxLevel:3,effect:e=>({extraAutoCrafts:e})},massTransport:{name:"Mass Transport",description:"+50% transport capacity per level",minRebirths:3,baseCost:40,costGrowth:2.8,maxLevel:5,effect:e=>({transportCapacity:1+.5*e})},thriftyBuilder:{name:"Thrifty Builder",description:"-10% building costs per level",minRebirths:3,baseCost:35,costGrowth:2.5,maxLevel:5,effect:e=>({buildingDiscount:1-.1*e})},goldenTouch:{name:"Golden Touch",description:"+25% gold earned from all sources",minRebirths:4,baseCost:100,costGrowth:3.5,maxLevel:4,effect:e=>({goldMultiplier:1+.25*e})},empireBuilder:{name:"Empire Builder",description:"Start with 100 gold per rebirth level",minRebirths:4,baseCost:80,costGrowth:3,maxLevel:10,effect:e=>({startingGold:100*e})},timeWarp:{name:"Time Warp",description:"Reduce cooldowns by 15% per level",minRebirths:4,baseCost:120,costGrowth:3.8,maxLevel:5,effect:e=>({cooldownReduction:1-.15*e})},legendarySkill:{name:"Legendary Skill",description:"All efficiency bonuses +50%",minRebirths:5,baseCost:200,costGrowth:4,maxLevel:3,effect:e=>({efficiencyBoost:1+.5*e})},instantCraft:{name:"Instant Craft",description:"10% chance to instantly complete crafting",minRebirths:5,baseCost:180,costGrowth:4.2,maxLevel:3,effect:e=>({instantCraftChance:.1*e})},decayResistance:{name:"Decay Resistance",description:"-20% decay accumulation per level",minRebirths:5,baseCost:150,costGrowth:3.5,maxLevel:4,effect:e=>({decayReduction:1-.2*e})},arcadeMaster:{name:"Arcade Master",description:"+20% bonus from arcade games",minRebirths:6,baseCost:250,costGrowth:4.5,maxLevel:5,effect:e=>({arcadeBonus:1+.2*e})},quantumEfficiency:{name:"Quantum Efficiency",description:"Workers produce 30% more",minRebirths:6,baseCost:300,costGrowth:4.8,maxLevel:4,effect:e=>({quantumWorkerBonus:1+.3*e})},megaCrafter:{name:"Mega Crafter",description:"Craft 2 extra items per auto-craft cycle",minRebirths:6,baseCost:280,costGrowth:4.5,maxLevel:3,effect:e=>({extraAutoCrafts:2*e})},ultimateGatherer:{name:"Ultimate Gatherer",description:"10% chance to gather 5x resources",minRebirths:7,baseCost:400,costGrowth:5,maxLevel:3,effect:e=>({megaGatherChance:.1*e})},cosmicMultiplier:{name:"Cosmic Multiplier",description:"+100% to all gold earnings",minRebirths:7,baseCost:500,costGrowth:5.5,maxLevel:3,effect:e=>({goldMultiplier:1+1*e})},voidResistance:{name:"Void Resistance",description:"Start with 50% decay filled",minRebirths:7,baseCost:350,costGrowth:4.8,maxLevel:5,effect:e=>({startingDecay:10*e})},transcendence:{name:"Transcendence",description:"All multipliers increased by 75%",minRebirths:8,baseCost:800,costGrowth:6,maxLevel:2,effect:e=>({transcendenceBonus:1+.75*e})},infiniteAutomation:{name:"Infinite Automation",description:"Automation speed 2x per level",minRebirths:8,baseCost:700,costGrowth:5.8,maxLevel:3,effect:e=>({automationSpeedMultiplier:Math.pow(2,e)})},realityBender:{name:"Reality Bender",description:"50% chance items cost nothing",minRebirths:8,baseCost:900,costGrowth:6.5,maxLevel:2,effect:e=>({freeCraftChance:.25*e})},voidMastery:{name:"Void Mastery",description:"Reach the void faster (2x decay)",minRebirths:9,baseCost:1500,costGrowth:7,maxLevel:3,effect:e=>({decayGeneration:1+1*e})},omnipotence:{name:"Omnipotence",description:"All bonuses doubled",minRebirths:9,baseCost:2e3,costGrowth:8,maxLevel:1,effect:e=>({omnipotenceBonus:e>0?2:1})},arcadeLegend:{name:"Arcade Legend",description:"Arcade time generates resources",minRebirths:9,baseCost:1800,costGrowth:7.5,maxLevel:5,effect:e=>({arcadeResourceGen:.1*e})}}}getUpgradeCost(e,t){const r=this.rebirthUpgrades[e];return r?Math.floor(r.baseCost*Math.pow(r.costGrowth,t)):1/0}getUpgradeDescription(e,t){const r=this.rebirthUpgrades[e];if(!r)return"";const a=t+1,n=t>0?r.effect(t):null,o=r.effect(a);switch(e){case"efficientGathering":return t>0?`Currently: +${Math.round(100*(n.gatheringSpeed-1))}% gathering speed | Next: +${Math.round(100*(o.gatheringSpeed-1))}%`:`+${Math.round(100*(o.gatheringSpeed-1))}% gathering speed per level`;case"quickCrafting":return t>0?`Currently: +${Math.round(100*(n.craftingSpeed-1))}% crafting speed | Next: +${Math.round(100*(o.craftingSpeed-1))}%`:`+${Math.round(100*(o.craftingSpeed-1))}% crafting speed per level`;case"shrewdTrader":return t>0?`Currently: +${Math.round(100*(n.sellingBonus-1))}% selling price | Next: +${Math.round(100*(o.sellingBonus-1))}%`:`+${Math.round(100*(o.sellingBonus-1))}% selling price per level`;case"masterCrafter":return t>0?`Currently: ${Math.round(100*n.doubleCraftChance)}% chance to craft 2x | Next: ${Math.round(100*o.doubleCraftChance)}%`:`${Math.round(100*o.doubleCraftChance)}% chance to craft 2x items per level`;case"luckyFind":return t>0?`Currently: ${Math.round(100*n.doubleGatherChance)}% chance to find 2x | Next: ${Math.round(100*o.doubleGatherChance)}%`:`${Math.round(100*o.doubleGatherChance)}% chance to find 2x resources per level`;case"fastLearner":return t>0?`Currently: +${Math.round(100*(n.workerEfficiency-1))}% worker efficiency | Next: +${Math.round(100*(o.workerEfficiency-1))}%`:`+${Math.round(100*(o.workerEfficiency-1))}% worker efficiency per level`;case"bulkProduction":return t>0?`Currently: Auto-craft ${n.extraAutoCrafts} extra items | Next: ${o.extraAutoCrafts}`:`Auto-craft ${o.extraAutoCrafts} items simultaneously per level`;case"massTransport":return t>0?`Currently: +${Math.round(100*(n.transportCapacity-1))}% transport capacity | Next: +${Math.round(100*(o.transportCapacity-1))}%`:`+${Math.round(100*(o.transportCapacity-1))}% transport capacity per level`;case"thriftyBuilder":return t>0?`Currently: ${Math.round(100*(1-n.buildingDiscount))}% building discount | Next: ${Math.round(100*(1-o.buildingDiscount))}%`:`${Math.round(100*(1-o.buildingDiscount))}% building discount per level`;case"goldenTouch":return t>0?`Currently: +${Math.round(100*(n.goldMultiplier-1))}% gold earned | Next: +${Math.round(100*(o.goldMultiplier-1))}%`:`+${Math.round(100*(o.goldMultiplier-1))}% gold earned per level`;case"empireBuilder":return t>0?`Currently: Start with ${n.startingGold} gold | Next: ${o.startingGold}`:`Start with ${o.startingGold} gold per level`;case"timeWarp":return t>0?`Currently: ${Math.round(100*(1-n.cooldownReduction))}% cooldown reduction | Next: ${Math.round(100*(1-o.cooldownReduction))}%`:`${Math.round(100*(1-o.cooldownReduction))}% cooldown reduction per level`;case"legendarySkill":return t>0?`Currently: +${Math.round(100*(n.efficiencyBoost-1))}% all efficiency | Next: +${Math.round(100*(o.efficiencyBoost-1))}%`:`+${Math.round(100*(o.efficiencyBoost-1))}% all efficiency per level`;case"instantCraft":return t>0?`Currently: ${Math.round(100*n.instantCraftChance)}% instant craft | Next: ${Math.round(100*o.instantCraftChance)}%`:`${Math.round(100*o.instantCraftChance)}% chance to instantly complete crafting per level`;case"decayResistance":return t>0?`Currently: ${Math.round(100*(1-n.decayReduction))}% less decay | Next: ${Math.round(100*(1-o.decayReduction))}%`:`${Math.round(100*(1-o.decayReduction))}% less decay per level`;case"arcadeMaster":return t>0?`Currently: +${Math.round(100*(n.arcadeBonus-1))}% arcade rewards | Next: +${Math.round(100*(o.arcadeBonus-1))}%`:`+${Math.round(100*(o.arcadeBonus-1))}% bonus from arcade games per level`;case"quantumEfficiency":return t>0?`Currently: Workers produce +${Math.round(100*(n.quantumWorkerBonus-1))}% more | Next: +${Math.round(100*(o.quantumWorkerBonus-1))}%`:`Workers produce +${Math.round(100*(o.quantumWorkerBonus-1))}% more per level`;case"megaCrafter":return t>0?`Currently: Craft ${n.extraAutoCrafts} extra items | Next: ${o.extraAutoCrafts}`:`Craft ${o.extraAutoCrafts} extra items per auto-craft cycle per level`;case"ultimateGatherer":return t>0?`Currently: ${Math.round(100*n.megaGatherChance)}% chance for 5x resources | Next: ${Math.round(100*o.megaGatherChance)}%`:`${Math.round(100*o.megaGatherChance)}% chance to gather 5x resources per level`;case"cosmicMultiplier":return t>0?`Currently: +${Math.round(100*(n.goldMultiplier-1))}% gold | Next: +${Math.round(100*(o.goldMultiplier-1))}%`:`+${Math.round(100*(o.goldMultiplier-1))}% to all gold earnings per level`;case"voidResistance":return t>0?`Currently: Start with ${n.startingDecay}% decay | Next: ${o.startingDecay}%`:`Start with ${o.startingDecay}% decay per level`;case"transcendence":return t>0?`Currently: +${Math.round(100*(n.transcendenceBonus-1))}% to all multipliers | Next: +${Math.round(100*(o.transcendenceBonus-1))}%`:`+${Math.round(100*(o.transcendenceBonus-1))}% to all multipliers per level`;case"infiniteAutomation":return t>0?`Currently: ${n.automationSpeedMultiplier}x automation speed | Next: ${o.automationSpeedMultiplier}x`:`${o.automationSpeedMultiplier}x automation speed per level`;case"realityBender":return t>0?`Currently: ${Math.round(100*n.freeCraftChance)}% free craft chance | Next: ${Math.round(100*o.freeCraftChance)}%`:`${Math.round(100*o.freeCraftChance)}% chance items cost nothing per level`;case"voidMastery":return t>0?`Currently: ${n.decayGeneration}x decay generation | Next: ${o.decayGeneration}x`:`${o.decayGeneration}x decay generation per level`;case"omnipotence":return t>0?"All bonuses doubled (ACTIVE)":"All bonuses doubled";case"arcadeLegend":return t>0?`Currently: ${Math.round(100*n.arcadeResourceGen)}% resource gen | Next: ${Math.round(100*o.arcadeResourceGen)}%`:`Arcade time generates ${Math.round(100*o.arcadeResourceGen)}% resources per level`;default:return r.description}}isUpgradeAvailable(e,t){const r=this.rebirthUpgrades[e];return!!r&&t>=r.minRebirths}getAvailableUpgrades(e){return Object.entries(this.rebirthUpgrades).filter(([t,r])=>e>=r.minRebirths).map(([e,t])=>({key:e,...t}))}getUpgradesByTier(e){const t={1:[],2:[],3:[],4:[],5:[],6:[],7:[],8:[],9:[]};return Object.entries(this.rebirthUpgrades).forEach(([r,a])=>{if(e>=a.minRebirths){const e=a.minRebirths;e<=9&&t[e].push({key:r,...a})}}),t}getActiveEffects(e){const t={gatheringSpeed:1,craftingSpeed:1,sellingBonus:1,doubleCraftChance:0,doubleGatherChance:0,workerEfficiency:1,extraAutoCrafts:0,transportCapacity:1,buildingDiscount:1,goldMultiplier:1,startingGold:0,cooldownReduction:1,efficiencyBoost:1,instantCraftChance:0,decayReduction:1,arcadeBonus:1,quantumWorkerBonus:1,megaGatherChance:0,cosmicMultiplier:1,startingDecay:0,transcendenceBonus:1,automationSpeedMultiplier:1,freeCraftChance:0,decayGeneration:1,omnipotenceBonus:1,arcadeResourceGen:0};return Object.entries(e).forEach(([e,r])=>{const a=this.rebirthUpgrades[e];if(a&&r>0){const e=a.effect(r);Object.entries(e).forEach(([e,r])=>{["gatheringSpeed","craftingSpeed","sellingBonus","workerEfficiency","transportCapacity","buildingDiscount","goldMultiplier","cooldownReduction","efficiencyBoost","decayReduction","arcadeBonus","quantumWorkerBonus","cosmicMultiplier","transcendenceBonus","automationSpeedMultiplier","decayGeneration","omnipotenceBonus"].includes(e)?t[e]*=r:t[e]+=r})}}),t.omnipotenceBonus>1&&Object.keys(t).forEach(e=>{["gatheringSpeed","craftingSpeed","sellingBonus","workerEfficiency","transportCapacity","goldMultiplier","efficiencyBoost","arcadeBonus","quantumWorkerBonus","cosmicMultiplier","transcendenceBonus","automationSpeedMultiplier"].includes(e)&&(t[e]*=t.omnipotenceBonus)}),t}calculateRebirthPower(e,t){const r=.05*e;let a=0;return Object.entries(t).forEach(([e,t])=>{this.rebirthUpgrades[e]&&t>0&&(a+=.1*t)}),{basePower:r,upgradePower:a,totalPower:r+a,multiplier:1+r+a}}}window.RebirthRewards=RebirthRewards;